# Cloud Firestore

Cloud Firestore is a NoSQL document database with real-time sync, offline support, and security rules. Data lives in collections of documents, each identified by a unique ID.

## Initialize Firestore

```typescript
import { initializeApp } from 'firebase/app';
import { getFirestore } from 'firebase/firestore';

const app = initializeApp({
  apiKey: process.env.FIREBASE_API_KEY,
  projectId: process.env.FIREBASE_PROJECT_ID,
});
const db = getFirestore(app);
```

## Data Model

Firestore organizes data hierarchically:

```
users (collection)
  ├─ userId1 (document)
  │   ├─ name: "Alice"
  │   ├─ email: "alice@example.com"
  │   └─ posts (subcollection)
  │       └─ postId1 (document)
  └─ userId2 (document)
```

Documents contain fields (string, number, boolean, timestamp, array, map, reference, geopoint). Max document size is 1 MB.

## Add a Document

```typescript
import { collection, addDoc } from 'firebase/firestore';

// Auto-generated ID
const docRef = await addDoc(collection(db, 'users'), {
  name: 'Alice',
  email: 'alice@example.com',
  age: 30,
  createdAt: serverTimestamp(),
});
console.log('Document ID:', docRef.id);
```

## Set a Document (with explicit ID)

```typescript
import { doc, setDoc } from 'firebase/firestore';

await setDoc(doc(db, 'users', 'alice-uid'), {
  name: 'Alice',
  email: 'alice@example.com',
  age: 30,
});

// Merge instead of overwrite
await setDoc(doc(db, 'users', 'alice-uid'), { age: 31 }, { merge: true });
```

## Get a Document

```typescript
import { doc, getDoc } from 'firebase/firestore';

const docSnap = await getDoc(doc(db, 'users', 'alice-uid'));
if (docSnap.exists()) {
  console.log('Data:', docSnap.data());
} else {
  console.log('Document not found');
}
```

## Query Documents

```typescript
import { collection, query, where, orderBy, limit, getDocs } from 'firebase/firestore';

const q = query(
  collection(db, 'users'),
  where('age', '>', 18),
  orderBy('name'),
  limit(10)
);

const snapshot = await getDocs(q);
snapshot.forEach((doc) => {
  console.log(doc.id, '=>', doc.data());
});
```

### Pagination with Cursors

```typescript
import { query, collection, orderBy, limit, startAfter, getDocs } from 'firebase/firestore';

// First page
const first = query(collection(db, 'users'), orderBy('name'), limit(25));
const firstSnap = await getDocs(first);
const lastDoc = firstSnap.docs[firstSnap.docs.length - 1];

// Next page
const next = query(collection(db, 'users'), orderBy('name'), startAfter(lastDoc), limit(25));
const nextSnap = await getDocs(next);
```

### Compound Queries

```typescript
// Equality + range (requires composite index)
const q = query(
  collection(db, 'posts'),
  where('status', '==', 'published'),
  where('likes', '>=', 10),
  orderBy('likes', 'desc')
);

// Array contains
const q2 = query(
  collection(db, 'posts'),
  where('tags', 'array-contains', 'firebase')
);

// In operator
const q3 = query(
  collection(db, 'users'),
  where('role', 'in', ['admin', 'editor'])
);
```

## Real-time Listener

```typescript
import { doc, collection, query, where, onSnapshot } from 'firebase/firestore';

// Listen to a single document
const unsub = onSnapshot(doc(db, 'users', 'alice-uid'), (docSnap) => {
  if (docSnap.exists()) {
    console.log('Current data:', docSnap.data());
  }
});

// Listen to a query
const unsubQuery = onSnapshot(
  query(collection(db, 'messages'), where('room', '==', 'general')),
  (snapshot) => {
    snapshot.docChanges().forEach((change) => {
      if (change.type === 'added') console.log('New:', change.doc.data());
      if (change.type === 'modified') console.log('Modified:', change.doc.data());
      if (change.type === 'removed') console.log('Removed:', change.doc.data());
    });
  }
);

// Stop listening
unsub();
unsubQuery();
```

## Update a Document

```typescript
import { doc, updateDoc, arrayUnion, arrayRemove, increment, serverTimestamp } from 'firebase/firestore';

await updateDoc(doc(db, 'users', 'alice-uid'), {
  age: 31,
  'address.city': 'San Francisco', // nested field
  tags: arrayUnion('premium'),      // add to array
  loginCount: increment(1),         // atomic increment
  updatedAt: serverTimestamp(),      // server timestamp
});

// Remove from array
await updateDoc(doc(db, 'users', 'alice-uid'), {
  tags: arrayRemove('trial'),
});
```

## Delete a Document

```typescript
import { doc, deleteDoc, deleteField, updateDoc } from 'firebase/firestore';

// Delete entire document
await deleteDoc(doc(db, 'users', 'alice-uid'));

// Delete a single field
await updateDoc(doc(db, 'users', 'alice-uid'), {
  age: deleteField(),
});
```

## Transactions

Transactions ensure atomic read-then-write operations:

```typescript
import { runTransaction, doc } from 'firebase/firestore';

await runTransaction(db, async (transaction) => {
  const postRef = doc(db, 'posts', postId);
  const postSnap = await transaction.get(postRef);

  if (!postSnap.exists()) throw new Error('Post not found');

  const newLikes = postSnap.data().likes + 1;
  transaction.update(postRef, { likes: newLikes });
});
```

## Batched Writes

Group up to 500 writes into a single atomic operation:

```typescript
import { writeBatch, doc, collection } from 'firebase/firestore';

const batch = writeBatch(db);

batch.set(doc(collection(db, 'users')), { name: 'Alice' });
batch.update(doc(db, 'counters', 'users'), { count: increment(1) });
batch.delete(doc(db, 'invites', inviteId));

await batch.commit();
```

## Security Rules

```
// firestore.rules
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Users can read/write their own documents
    match /users/{userId} {
      allow read: if request.auth != null;
      allow write: if request.auth.uid == userId;
    }

    // Posts: anyone can read published, only author can write
    match /posts/{postId} {
      allow read: if resource.data.status == 'published'
                  || request.auth.uid == resource.data.authorId;
      allow create: if request.auth != null
                    && request.resource.data.authorId == request.auth.uid;
      allow update, delete: if request.auth.uid == resource.data.authorId;
    }

    // Helper function
    function isAdmin() {
      return request.auth.token.admin == true;
    }

    match /admin/{document=**} {
      allow read, write: if isAdmin();
    }
  }
}
```

## Composite Indexes

Compound queries (equality on one field + range/orderBy on another) require composite indexes. Firestore auto-suggests missing indexes in error messages. Define them in `firestore.indexes.json`:

```json
{
  "indexes": [
    {
      "collectionGroup": "posts",
      "queryScope": "COLLECTION",
      "fields": [
        { "fieldPath": "status", "order": "ASCENDING" },
        { "fieldPath": "likes", "order": "DESCENDING" }
      ]
    }
  ]
}
```

## Offline Persistence

```typescript
import { enableIndexedDbPersistence, getFirestore } from 'firebase/firestore';

const db = getFirestore(app);
await enableIndexedDbPersistence(db).catch((err) => {
  if (err.code === 'failed-precondition') {
    // Multiple tabs open — only one can use persistence
  } else if (err.code === 'unimplemented') {
    // Browser doesn't support IndexedDB
  }
});
```
